#include<bits/stdc++.h>
using namespace std;
int fa[110],cha[110];
int find(int x)
{
    if(x!=fa[x])
    {
        int t=find(fa[x]);
        cha[x]+=cha[fa[x]];
        return fa[x]=t;
    }
    return fa[x];
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,m,flag=0;
        scanf("%d%d",&n,&m);
        for(int i=0;i<=n;i++)
        {
            fa[i]=i;
            cha[i]=0;
        }
        for(int i=1;i<=m;i++)
        {
            int x,y,z;
            scanf("%d%d%d",&x,&y,&z);
            x--;
            if(find(x)!=find(y))
            {
                cha[fa[y]]=cha[x]-cha[y]-z;
                fa[fa[y]]=fa[x];
            }
            else if(cha[x]-cha[y]!=z)
            {
                flag=1;
            }
        }
        if(flag==0)
        {
            printf("true\n");
        }
        else
        {
            printf("false\n");
        }
    }
    return 0;
}
